<main class="public-profile-page"><section class="public-profile-card"><?=chat_avatar_html($channel,null,'public-avatar')?><h1><?=e($channel['title'])?></h1><?php if(!empty($channel['username'])):?><p class="public-username">@<?=e($channel['username'])?></p><?php endif;?><p><?=e($channel['description']??'')?></p><div class="public-stats"><span><b><?=(int)$subscribers?></b><small>подписчиков</small></span></div><?php if(\Kovcheg\Auth::check()):?><?php if($isMember):?><a class="btn btn-primary" href="<?=e(chat_public_url($channel,\Kovcheg\Auth::id()))?>">Открыть канал</a><?php elseif($channel['join_policy']==='open'):?><form method="post" action="<?=e(app_url('/channel/'.$channel['id'].'/join'))?>"><?=csrf_field()?><button class="btn btn-primary">Подписаться</button></form><?php elseif($channel['join_policy']==='request'):?><form method="post" action="<?=e(app_url('/channel/'.$channel['id'].'/request'))?>"><?=csrf_field()?><button class="btn btn-primary"><?=$hasRequest?'Заявка отправлена':'Отправить заявку'?></button></form><?php else:?><p class="muted">Вступление доступно по приглашению.</p><?php endif;?><?php else:?><a class="btn btn-primary" href="<?=e(app_url('/login'))?>">Войти</a><?php endif;?></section></main>